import React, { useState, useCallback } from 'react';
import { Button, Select, dispatchAppToast } from '@linm-soft/common-components';
import { hasPermissionCode, usePeriodJobPermissions } from '../../../hooks/usePeriodJobPermissions';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import type { DepreciationDto } from '../../../services/tscd/models';
import type { PeriodProcessDocumentsDto } from '../../../services/kt/models';
import { PeriodProcessDocumentsSection } from '../../../components/kt/PeriodProcessDocumentsSection';
import { DocumentProcessingLevelPill } from '../../../components/document/DocumentProcessingLevelPill';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';
import { tscdPageLabels as L } from '../../../constants/tscdPageLabels';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import {
  DOCUMENT_PREPARED_LEVEL,
  formatDepreciationProcessingLevel,
  isFinalDocumentProcessingLevel,
} from '../../../utils/documentProcessingLevelDisplay';
import erp from '../../../styles/erpPage.module.css';
import df from '../../../styles/documentForm.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const TEST_ID = 'erp-khau-hao';

const KhauHaoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { canRun: runPermitted, canPost: postPermitted } = usePeriodJobPermissions('depreciation');
  void hasPermissionCode;
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [data, setData] = useState<DepreciationDto | null>(null);
  const [documents, setDocuments] = useState<PeriodProcessDocumentsDto | null>(null);
  const [loading, setLoading] = useState(false);
  const [documentsLoading, setDocumentsLoading] = useState(false);
  const [running, setRunning] = useState(false);
  const [posting, setPosting] = useState(false);

  const loadDocuments = useCallback((m: number, y: number, processingLevel: string | null | undefined) => {
    if (!isFinalDocumentProcessingLevel(processingLevel)) {
      setDocuments(null);
      return;
    }
    setDocumentsLoading(true);
    tscdService.getDepreciationDocuments(m, y)
      .then(setDocuments)
      .catch(() => setDocuments(null))
      .finally(() => setDocumentsLoading(false));
  }, []);

  const load = useCallback(() => {
    setLoading(true);
    const m = Number(month);
    const y = Number(year);
    tscdService.getDepreciation(m, y)
      .then(d => {
        setData(d);
        loadDocuments(m, y, d.processingLevel);
      })
      .catch(err => dispatchAppToast(dispatch, { message: getApiErrorMessage(err, L.khauHao.loadError), type: 'error' }))
      .finally(() => setLoading(false));
  }, [month, year, dispatch, loadDocuments]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const processingLevel = data?.processingLevel ?? null;
  const canRun = !isFinalDocumentProcessingLevel(processingLevel);
  const canPost = processingLevel === DOCUMENT_PREPARED_LEVEL;
  const hasLines = (data?.lines.length ?? 0) > 0;
  const isEmptyPeriod = !processingLevel && !hasLines;

  const handleRun = async () => {
    setRunning(true);
    try {
      await tscdService.runDepreciation(Number(month), Number(year));
      dispatchAppToast(dispatch, { message: L.khauHao.runSuccess, type: 'success' });
      load();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, L.khauHao.runError), type: 'error' });
    } finally {
      setRunning(false);
    }
  };

  const handlePost = async () => {
    setPosting(true);
    try {
      await tscdService.postDepreciation(Number(month), Number(year));
      dispatchAppToast(dispatch, { message: L.khauHao.postSuccess, type: 'success' });
      load();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, L.khauHao.postError), type: 'error' });
    } finally {
      setPosting(false);
    }
  };

  return (
    <div className={erp.page} data-testid={TEST_ID}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-chart-line" /> {L.khauHao.title}</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} data-testid={`${TEST_ID}-month`} />
        <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} data-testid={`${TEST_ID}-year`} />
        {runPermitted && (
          <Button variant="primary" onClick={handleRun} loading={running} disabled={!canRun} data-testid={`${TEST_ID}-run`}>{L.khauHao.run}</Button>
        )}
        {postPermitted && (
          <Button variant="secondary" onClick={handlePost} loading={posting} disabled={!canPost} data-testid={`${TEST_ID}-post`}>{L.khauHao.post}</Button>
        )}
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={load} onRefresh={load} showSearch={false} />
      </div>
      <div className={erp.tableCard} data-testid={`${TEST_ID}-table`}>
        {loading ? <div className={erp.loading}>{L.khauHao.loading}</div> : !data || isEmptyPeriod ? (
          <div className={erp.empty}>{L.khauHao.empty(month, year)}</div>
        ) : (
          <>
            <div className={erp.summaryBar}>
              <div className={erp.summaryItem}>
                <label className={erp.label}>{L.khauHao.processingLevel}</label>
                <DocumentProcessingLevelPill
                  label={formatDepreciationProcessingLevel(processingLevel)}
                  testId={`${TEST_ID}-level`}
                />
              </div>
              <div className={erp.summaryItem}><label className={erp.label}>{L.khauHao.total}</label><strong>{formatVnd(data.totalAmount)}</strong></div>
            </div>
            {hasLines ? (
              <>
                <div className={df.section} style={{ margin: '0 0 12px', padding: '12px 16px' }}>
                  <h2 className={df.sectionTitle}>{L.khauHao.methodTitle}</h2>
                  <p style={{ margin: 0, fontSize: 13, lineHeight: 1.5 }}>{L.khauHao.methodNote}</p>
                </div>
                <div className={erp.tableWrapper}>
                <table className={erp.table}>
                  <thead><tr><th>{L.khauHao.colCode}</th><th>{L.khauHao.colName}</th><th>{L.khauHao.colAccount}</th><th className={erp.colRight}>{L.khauHao.colOriginalCost}</th><th className={erp.colRight}>{L.khauHao.colAmount}</th><th className={erp.colRight}>{L.khauHao.colAccumDep}</th><th className={erp.colRight}>{L.khauHao.colBookValue}</th></tr></thead>
                  <tbody>{data.lines.map(l => (
                    <tr key={l.fixedAssetId} data-testid={`${TEST_ID}-row-${l.fixedAssetId}`}>
                      <td><code>{l.assetCode}</code></td>
                      <td>{l.assetName}</td>
                      <td><code>{l.accountCode}</code></td>
                      <td className={erp.colRight}>{formatVnd(l.originalCost)}</td>
                      <td className={erp.colRight}>{formatVnd(l.amount)}</td>
                      <td className={erp.colRight}>{formatVnd(l.accumulatedDepreciation)}</td>
                      <td className={erp.colRight}><strong>{formatVnd(l.bookValue)}</strong></td>
                    </tr>
                  ))}</tbody>
                </table>
              </div>
              </>
            ) : (
              <div className={erp.empty}>{L.khauHao.noLines}</div>
            )}
          </>
        )}
      </div>
      {isFinalDocumentProcessingLevel(processingLevel) && (
        <PeriodProcessDocumentsSection
          documents={documents}
          loading={documentsLoading}
          testIdPrefix={`${TEST_ID}-docs`}
          emptyMessage={L.khauHao.docsEmpty}
        />
      )}
    </div>
  );
};

export default KhauHaoPage;
